'''
Brute Force Solution
Complexity: O(n3)
Issue: TLE
'''
def solve():
    s = "babad"
    # s = "bananas"
    # s = ""
    
    if len(s) < 1:
        return s
   
    i = 0
    longest_candidate = s[0]
    while i < len(s):
        j = i
        while j < len(s):
            candidate = s[i:j+1]
            if candidate == candidate[::-1] and len(candidate) > 1:
                if len(candidate) > len(longest_candidate):
                    longest_candidate = candidate
            j += 1
        i += 1
        
    return longest_candidate
   
        
print(solve())